import { ChangeDetectorRef, Component, OnInit, ViewChild } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { IonCheckbox } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { VendorService } from "src/app/core/services/vendor.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import {
  DuplicateContract,
  VendorBranchInfo,
  VendorContract,
  VendorContractBranchRequest,
  VendorInfo,
} from "src/app/views/Models/Vendor/consumer";

@Component({
  selector: "app-manage-vendor-contracts",
  templateUrl: "./manage-vendor-contracts.page.html",
  styleUrls: ["./manage-vendor-contracts.page.scss"],
})
export class ManageVendorContractsPage implements OnInit {
  @ViewChild("ionCheckBoxBranches") ionCheckBoxBranches: IonCheckbox;

  //#region Flags
  showLoader: boolean = false;
  showVendors: boolean = false;
  showContracts: boolean = false;
  showAddContractModal: boolean = false;
  showEditContractModal: boolean = false;
  showAddContractBranchModal: boolean = false;
  //#endregion
  //#region Variables
  vendors: VendorInfo[];
  filteredVendors: VendorInfo[];
  vendorPage: number = 1;
  searchVendor: string = "";
  vendorContract: VendorContract[];
  selectedVendor: VendorInfo;
  contractPage: number = 1;
  selectedRowIndex: number = -1;
  vendorBranch: Array<VendorBranchInfo & { isChecked: boolean }>;
  selectedVendorContract: VendorContract;
  vendorBranchPage: number = 1;
  selectedBranches: VendorBranchInfo[] = [];
  ActiveBranches: VendorBranchInfo[] = [];
  //#endregion

  //#region Forms
  ContractForm: FormGroup = this.formbuilder.group({
    orgCode: [null, Validators.required],
    vendorCode: [null, Validators.required],
    vendContractCode: [null],
    contractStartDate: ["", Validators.required],
    contractEndDate: ["", Validators.required],
    authorizedPerson: [""],
    authorizedIdNo: [""],
    mailingAddress: [""],
    comPercent: [""],
    comAm: [""],
    minSalesAm: [""],
    activeRec: [0],
  });
  //#endregion
  constructor(
    private vendorService: VendorService,
    public pagingService: pagingService,
    private alertService: AlertService,
    private cdref: ChangeDetectorRef,
    private formbuilder: FormBuilder,
    private referencesService: ReferencesService,
    public inputMaskingService: InputMaskingService,
    private authService: MohassilAuthService
  ) {}

  async ngOnInit() {
    this.showLoader = true;
    await this.vendorService.getActiveVendors().then((res) => {
      this.vendors = res;
      this.filteredVendors = res;
      this.showVendors = true;
    });
    this.showLoader = false;
  }

  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }

  search($event: Event) {
    const input = $event.target as HTMLInputElement;
    this.searchVendor = input.value;
    this.vendorPage = 1;

    this.filteredVendors = this.vendors.filter(
      (v) =>
        this.searchVendor == "" ||
        v.vendor_name.toLowerCase().match(this.searchVendor.toLowerCase())
    );
  }

  async openVendor(vendor: VendorInfo) {
    this.showLoader = true;
    this.selectedVendor = vendor;
    await this.vendorService
      .getVendorContracts(vendor.vendor_code)
      .then((res) => {
        this.vendorContract = res;
        this.showContracts = true;
        this.showVendors = false;
        this.showLoader = false;
      })
      .catch((err) => {
        console.error(err);
        this.showLoader = false;
      });
  }

  changeVendorPage(newPage: number): void {
    this.vendorPage = newPage;
  }

  changeContractPage(newPage: number): void {
    this.contractPage = newPage;
  }

  backToVendors() {
    this.showContracts = false;
    this.showVendors = true;
    this.contractPage = 1;
    this.vendorContract = [];
  }

  selectGridRow(index: number) {
    this.selectedRowIndex = index;
  }

  getRowClasses(vendor: VendorContract, index: number): string[] {
    const isActive = vendor.activeRec === 1;
    const isSelected = this.selectedRowIndex === index;

    if (isActive && isSelected) return ["active-selected"];
    if (isActive) return ["active-contract"];
    if (isSelected) return ["highlighted-row"];
    return [];
  }

  async openAddContractModal() {
    this.showAddContractModal = true;
    this.showEditContractModal = false;
    this.ContractForm.reset();
    this.ContractForm.patchValue({
      orgCode: (await this.authService.getUserInfo()).org_code,
      vendorCode: this.selectedVendor.vendor_code,
      vendContractCode: this.vendorContract
        ? this.vendorContract.length + 1
        : 1,
    });
  }
  openEditContractModal(vendor: VendorContract) {
    this.showAddContractModal = false;
    this.showEditContractModal = true;
    this.ContractForm.reset();
    this.ContractForm.patchValue({
      orgCode: vendor.orgCode,
      vendorCode: vendor.vendorCode,
      vendContractCode: vendor.vendContractCode,
      contractStartDate: vendor.contractStartDate,
      contractEndDate: vendor.contractEndDate,
      authorizedPerson: vendor.authorizedPerson,
      authorizedIdNo: vendor.authorizedIdNo,
      mailingAddress: vendor.mailingAddress,
      comPercent: vendor.comPercent,
      comAm: vendor.comAm,
      minSalesAm: vendor.minSalesAm,
      activeRec: vendor.activeRec === 1 ? true : false,
    });
    this.selectedRowIndex = -1;
  }

  closeModal() {
    this.showAddContractModal = false;
    this.showEditContractModal = false;
    this.ContractForm.reset();
  }

  async DuplicateContract(vendor: VendorContract) {
    if (
      await this.alertService.SaveAlert(
        "هل تريداضافة عقد جديد بنفس بنود هذا العقد؟"
      )
    ) {
      this.showLoader = true;
      let request: DuplicateContract = {
        vendorCode: vendor.vendorCode,
        vendContractCode: vendor.vendContractCode,
      };
      await this.vendorService
        .duplicateVendorContract(request)
        .then(async () => {
          this.closeModal();
          await this.openVendor(this.selectedVendor);
          await this.alertService.showAlertConfirm("تم الاضافة بنجاح", false);
        })
        .catch(async (err) => {
          console.error(err);
          await this.alertService.showAlertError(err.error, false);
        });
      this.showLoader = false;
    }
  }

  async addContract() {
    if (this.ContractForm.valid) {
      this.showLoader = true;
      let contractActiveRec = this.vendorContract.find((x) => x.activeRec === 1)
        ? 0
        : 1;
      let request: VendorContract = {
        orgCode: this.ContractForm.value.orgCode,
        vendorCode: this.ContractForm.value.vendorCode,
        vendContractCode: this.ContractForm.value.vendContractCode,
        contractStartDate: this.ContractForm.value.contractStartDate,
        contractEndDate: this.ContractForm.value.contractEndDate,
        authorizedPerson: this.ContractForm.value.authorizedPerson,
        authorizedIdNo: this.ContractForm.value.authorizedIdNo,
        mailingAddress: this.ContractForm.value.mailingAddress,
        comPercent: this.ContractForm.value.comPercent ?? 0,
        comAm: this.ContractForm.value.comAm ?? 0,
        minSalesAm: this.ContractForm.value.minSalesAm ?? 0,
        activeRec: contractActiveRec,
      };
      await this.vendorService
        .addVendorContract(request)
        .then((res) => {
          this.showLoader = false;
          this.alertService.showAlertConfirm("تم الاضافة بنجاح", false);
          this.closeModal();
          this.openVendor(this.selectedVendor);
        })
        .catch(async (err) => {
          console.error(err);
          this.showLoader = false;
          await this.alertService.showAlertError(err.error, false);
        });
    } else {
      await this.alertService.showAlertError(
        "يجب ادخال تاريخ بداية العقد وتاريخ نهاية العقد",
        false
      );
    }
  }

  async editContract() {
    if (this.ContractForm.valid) {
      this.showLoader = true;
      let request: VendorContract = {
        orgCode: this.ContractForm.value.orgCode,
        vendorCode: this.ContractForm.value.vendorCode,
        vendContractCode: this.ContractForm.value.vendContractCode,
        contractStartDate: this.ContractForm.value.contractStartDate,
        contractEndDate: this.ContractForm.value.contractEndDate,
        authorizedPerson: this.ContractForm.value.authorizedPerson,
        authorizedIdNo: this.ContractForm.value.authorizedIdNo,
        mailingAddress: this.ContractForm.value.mailingAddress,
        comPercent: this.ContractForm.value.comPercent,
        comAm: this.ContractForm.value.comAm,
        minSalesAm: this.ContractForm.value.minSalesAm,
        activeRec: this.ContractForm.value.activeRec === true ? 1 : 0,
      };
      await this.vendorService
        .editVendorContract(request)
        .then(() => {
          this.showLoader = false;
          this.alertService.showAlertConfirm("تم التعديل بنجاح", false);
          this.closeModal();
          this.openVendor(this.selectedVendor);
        })
        .catch(async (err) => {
          console.error(err);
          this.showLoader = false;
          await this.alertService.showAlertError(err.error, false);
        });
    } else {
      await this.alertService.showAlertError(
        "يجب ادخال تاريخ بداية العقد وتاريخ نهاية العقد",
        false
      );
    }
  }

  async AddContractBranch(vendor: VendorContract) {
    this.showLoader = true;
    this.showAddContractBranchModal = true;
    this.selectedVendorContract = vendor;
    await this.vendorService
      .getActiveVendorBranches(vendor.vendorCode)
      .then(async (res) => {
        this.vendorBranch = this.vendorBranch = res.map((x) => ({
          ...x,
          isChecked: false,
        }));
        await this.vendorService
          .getActiveVendorContractBranches(vendor.vendorCode)
          .then((res) => {
            this.ActiveBranches = res;
            this.vendorBranch.forEach((br) => {
              if (
                this.ActiveBranches.find(
                  (ab) => ab.vendorBrCode === br.vendorBrCode
                )
              ) {
                br.isChecked = true;
              }
            });
          });
      })
      .catch((err) => {
        console.error(err);
        this.alertService.showAlertError(err.error, false);
      })
      .finally(() => {
        this.showLoader = false;
      });
  }

  closeBranchModal() {
    this.showAddContractBranchModal = false;
    this.vendorBranch = [];
    this.selectedBranches = [];
    this.vendorBranchPage = 1;
    this.ionCheckBoxBranches.checked = false;
  }

  async addContractBranches() {
    if (this.selectedBranches.length > 0) {
      if (await this.alertService.SaveAlert("هل تريد الحفظ؟")) {
        this.showLoader = true;
        let request: VendorContractBranchRequest = {
          vendorCode: this.selectedVendorContract.vendorCode,
          vendorContractCode: this.selectedVendorContract.vendContractCode,
          vendorBrCode: this.selectedBranches
            .map((c) => c.vendorBrCode.toString())
            .join(","),
        };
        await this.vendorService
          .AddVendorContractBranch(request)
          .then(async () => {
            await this.alertService.showAlertConfirm("تم الحفظ بنجاح", false);
          })
          .catch(async (err) => {
            console.log(err.error);
            await this.alertService.showAlertError(err.error, false);
            return;
          })
          .finally(() => {
            this.showLoader = false;
          });
      }
    } else {
      await this.alertService.showAlertError(
        "يجب اختيار فرع واحد على الاقل",
        false
      );
    }
  }

  //region Checbox Branches
  set isAllBranchesSelected(value: boolean) {
    this.vendorBranch.forEach((br) => (br.isChecked = value));
  }
  onBranchesCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.vendorBranch.forEach((br) => (br.isChecked = isChecked));
    this.updateSelectedBranchesForAll(isChecked);
  }
  updateSelectedBranchesForAll(isChecked: boolean) {
    this.selectedBranches = [];
    if (isChecked) {
      this.vendorBranch.forEach((br) => {
        this.selectedBranches.push(br);
      });
    }
  }
  onBranchCheckboxChange(event: any, br: any, index: any) {
    const selectedApp =
      this.vendorBranch[
        index + this.pagingService.pageSize * (this.vendorBranchPage - 1)
      ];

    selectedApp.isChecked = event.target.checked;
    this.updateSelectedBranch(br, event.target.checked);
    this.updateBranchMasterCheckbox();
    if (this.vendorBranch.length !== this.selectedBranches.length) {
      if (this.selectedBranches.length === 0) {
        this.ionCheckBoxBranches.indeterminate = false;
      } else {
        this.ionCheckBoxBranches.indeterminate = true;
      }
    } else if (this.vendorBranch.length === this.selectedBranches.length) {
      this.ionCheckBoxBranches.indeterminate = false;
      this.ionCheckBoxBranches.checked = true;
      this.isAllBranchesSelected = true;
    }
  }
  updateSelectedBranch(br: any, isChecked: boolean) {
    const index = this.selectedBranches!.indexOf(br);
    if (isChecked && index === -1) {
      this.selectedBranches.push(br);
    } else if (!isChecked && index > -1) {
      this.selectedBranches.splice(index, 1);
    }
  }
  updateBranchMasterCheckbox() {
    const allSelected = this.vendorBranch.every((app) => app.isChecked);
    const someSelected = this.vendorBranch.some((app) => app.isChecked);

    if (allSelected) {
      this.isAllBranchesSelected = true;
    } else if (!someSelected) {
      this.ionCheckBoxBranches.checked = false;
      this.ionCheckBoxBranches.indeterminate = false;
      this.isAllBranchesSelected = false;
    }
  }

  changeBranchPage(newPage: number): void {
    this.vendorBranchPage = newPage;
  }
  //endregion
}
